VALUES
  ('judicial-57112235-moex-00717', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '十八世紀中葉以降，由於刑事司法思潮演進，促使監獄進行改革，有助於監獄學積極發展的原因， 下列敘述何者錯誤？', '["獄政改革聲浪之鼓吹", "刑事政策觀念之發生", "人權主義思想之發達", "機械連帶及個人安全"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00718', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '下列何者是提出監獄教化矯治無效論（NothingWorks）的學者？', '["大衛華德（DavidWard,1967）", "馬丁森（RobertMartinson,1974）", "卡冷與堅德爾（Cullen&Gendreau,1977）", "麥克納瑪拉（DonaldMacNamara,1976）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00719', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關監獄假釋的功能，下列敘述何者錯誤？', '["可疏減監獄擁擠", "可穩定囚情維持紀律", "補救短刑期的缺失", "鼓勵長刑期受刑人改過自新 20720"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00720', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於隨母入監（含在監分娩）子女之處遇措施，下列敘述何者錯誤？', '["女子監獄備有育兒設施，開設親職及幼兒發展教育課程，並提供生活照顧、醫療照護等協助", "入監子女所需輔育費用均由監獄編列預算支應", "縣市社福主管機關辦理訪視評估及轉銜服務等，以促進兒福權益之保障", "子女戶籍所在地直轄市、縣（市）社會福利主管機關對於在監子女照顧安置事項，應提供必要 之協助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00721', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '關於酒癮受刑人入監後常見現象及處置作為，下列敘述何者錯誤？', '["48小時內出現戒斷症狀，第3天最為嚴重，且經常持續5至7天", "最初顯現症狀是異常興奮，情緒焦躁不安，甚至大吼大叫，類似毒癮發作", "如出現譫妄、意識錯亂等急性症候群，易引發衝動性自傷行為，應緊急通知家屬領回", "嗜酒成癮者多係個人獨處或隻身避居在外，家族支持性療法最具安撫與慰藉效用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00722', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關我國矯正機構之作業規定，下列敘述何者錯誤？', '["我國矯正機構之作業著重營利而非教化之目的，為勞動生產增加國庫之收入，看守所及監獄之 收容人一律命令參與作業", "我國受刑人作業每日不得逾8小時，但有特殊情形，得將作業時間延長之", "監獄應與受刑人晤談後，於個別處遇計畫中訂定適當作業項目", "參加作業者應給予勞作金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00723', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '犯罪矯正輔導技術中，關於代幣法（TokenEconomies）之敘述，下列何者錯誤？', '["以增強及削弱原則為基礎，強調以當事人所想要之東西為替代物", "以利用代幣為增強物，藉以發展適當行為", "藉著取消代幣來消除或減輕當事人不良行為", "由當事人與機構訂定契約，倘其有良好表現，即可接受優厚處遇"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00724', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '有關受刑人監禁權利與監獄管理動態平衡關係之敘述，下列何者錯誤？', '["受刑人人權是衡量獄政進步與否的重要指標", "受刑人人權受「聯合國在監人處遇最低標準規則」及曼德拉規則等國際公約準則所宣示保障， 故受刑人社會復歸之個別化處遇不再受到重視", "持續透過對受刑人人權議題的關注與選擇，方足以在封閉保守的監獄環境中激起改革的動力", "國際公約準則、輿論團體的關切、受刑人的抗爭等均可能影響受刑人的人權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00725', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '區域管理（UnitManagement）由於兼顧管理與受刑人處遇之需求，而為近年矯正實務界所青睞， 有關區域管理特色之敘述，下列何者錯誤？', '["受刑人與職員有較佳的互動關係，較少摩擦", "同類受刑人之聚居，有利於教化工作之進行", "適合管理之需要，有助於掌握受刑人之動態", "各區域受刑人以不超過30名為原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00726', 'judicial-57112235', 'judicial-57112235-moex-110-b098244d', 'sub-judicial-57112235-03', NULL, 'single_choice', '學者高夫曼（Goffman,1961）在總體機構的觀察中，認為受刑人具有以下類型之生活適應的呈現， 下列敘述何者錯誤？', '["情境退化型：從現實環境中退縮，拒絕與外界溝通", "非妥協型：此乃受刑人退化至其他類型之先發徵兆", "轉化型：利用服刑的機會以尋求其自身心靈之淨化", "殖民型：將入監服刑視為一種旅行，甚至沉溺其中 20720"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "a87f539596c4", "answer_pdf_sha1": "89ee3641f854", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0707", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "監獄學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
